namespace sv_79ab356b9e2a41af8681d336fae5e859.Services;

public enum Severity
{
    Info,
    Warning,
    Critical
}

public class Notification
{
    public Guid Id { get; init; } = Guid.NewGuid();
    public required string Title { get; init; }
    public required string Message { get; init; }
    public Severity Severity { get; init; }
    public bool IsRead { get; set; }
    public DateTime Timestamp { get; init; } = DateTime.UtcNow;
}

/// <summary>
/// Scoped per circuit. Holds shared notification state and notifies all
/// subscribed components via an event when state changes.
/// </summary>
public class NotificationHub
{
    private readonly List<Notification> _notifications = [];
    private readonly Lock _lock = new();

    /// <summary>
    /// Components subscribe to this event to be notified of ANY state change.
    /// The callback is invoked on a threadpool thread — subscribers must marshal
    /// to the UI synchronization context themselves (InvokeAsync).
    /// </summary>
    public event Func<Task>? OnChange;

    public IReadOnlyList<Notification> Notifications
    {
        get
        {
            lock (_lock)
            {
                return _notifications.ToList().AsReadOnly();
            }
        }
    }

    public int GetUnreadCount()
    {
        lock (_lock)
        {
            return _notifications.Count(n => !n.IsRead);
        }
    }

    public void AddNotification(string title, string message, Severity severity)
    {
        lock (_lock)
        {
            _notifications.Insert(0, new Notification
            {
                Title = title,
                Message = message,
                Severity = severity
            });
        }
        _ = NotifySubscribers();
    }

    public void MarkAsRead(Guid id)
    {
        lock (_lock)
        {
            var notification = _notifications.FirstOrDefault(n => n.Id == id);
            if (notification is not null)
                notification.IsRead = true;
        }
        _ = NotifySubscribers();
    }

    public void MarkAllRead()
    {
        lock (_lock)
        {
            foreach (var n in _notifications)
                n.IsRead = true;
        }
        _ = NotifySubscribers();
    }

    public void DismissNotification(Guid id)
    {
        lock (_lock)
        {
            _notifications.RemoveAll(n => n.Id == id);
        }
        _ = NotifySubscribers();
    }

    private async Task NotifySubscribers()
    {
        if (OnChange is not null)
        {
            // Invoke all subscribers; each is responsible for marshalling to its own sync context
            var delegates = OnChange.GetInvocationList().Cast<Func<Task>>();
            foreach (var handler in delegates)
            {
                try
                {
                    await handler();
                }
                catch
                {
                    // Swallow exceptions from disposed components
                }
            }
        }
    }
}

namespace sv_79ab356b9e2a41af8681d336fae5e859.Services;

/// <summary>
/// Scoped service that simulates server-push events by adding a random
/// notification every 15 seconds. Started/stopped by the dashboard page.
/// Runs on a non-UI thread — the NotificationHub event handles marshalling.
/// </summary>
public class SimulatorService : IDisposable
{
    private readonly NotificationHub _hub;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;

    private static readonly string[] Titles =
    [
        "Server Alert", "Deployment Update", "Security Notice",
        "Performance Warning", "System Health", "Backup Complete",
        "New User Signup", "Disk Usage Alert", "API Rate Limit",
        "Certificate Expiry"
    ];

    private static readonly string[] Messages =
    [
        "CPU usage exceeded 90% on node-3.",
        "Deployment v2.4.1 rolled out successfully.",
        "Failed login attempt from unknown IP.",
        "Response time degraded in /api/orders.",
        "All health checks passing.",
        "Daily backup completed without errors.",
        "New enterprise customer registered.",
        "Disk usage at 85% on volume /data.",
        "API rate limit reached for client X.",
        "TLS certificate expires in 7 days."
    ];

    public SimulatorService(NotificationHub hub)
    {
        _hub = hub;
    }

    public void Start()
    {
        if (_timer is not null) return;

        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(15));

        _ = RunAsync(_cts.Token);
    }

    public void Stop()
    {
        _cts?.Cancel();
        _timer?.Dispose();
        _timer = null;
        _cts?.Dispose();
        _cts = null;
    }

    private async Task RunAsync(CancellationToken ct)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                var rng = Random.Shared;
                var title = Titles[rng.Next(Titles.Length)];
                var message = Messages[rng.Next(Messages.Length)];
                var severity = (Severity)rng.Next(3);

                _hub.AddNotification(title, message, severity);
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on stop/dispose
        }
    }

    public void Dispose()
    {
        Stop();
    }
}

