namespace sv_79ab356b9e2a41af8681d336fae5e859.Services;

/// <summary>
/// Scoped service that simulates server-push events by adding a random
/// notification every 15 seconds. Started/stopped by the dashboard page.
/// Runs on a non-UI thread — the NotificationHub event handles marshalling.
/// </summary>
public class SimulatorService : IDisposable
{
    private readonly NotificationHub _hub;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;

    private static readonly string[] Titles =
    [
        "Server Alert", "Deployment Update", "Security Notice",
        "Performance Warning", "System Health", "Backup Complete",
        "New User Signup", "Disk Usage Alert", "API Rate Limit",
        "Certificate Expiry"
    ];

    private static readonly string[] Messages =
    [
        "CPU usage exceeded 90% on node-3.",
        "Deployment v2.4.1 rolled out successfully.",
        "Failed login attempt from unknown IP.",
        "Response time degraded in /api/orders.",
        "All health checks passing.",
        "Daily backup completed without errors.",
        "New enterprise customer registered.",
        "Disk usage at 85% on volume /data.",
        "API rate limit reached for client X.",
        "TLS certificate expires in 7 days."
    ];

    public SimulatorService(NotificationHub hub)
    {
        _hub = hub;
    }

    public void Start()
    {
        if (_timer is not null) return;

        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(15));

        _ = RunAsync(_cts.Token);
    }

    public void Stop()
    {
        _cts?.Cancel();
        _timer?.Dispose();
        _timer = null;
        _cts?.Dispose();
        _cts = null;
    }

    private async Task RunAsync(CancellationToken ct)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                var rng = Random.Shared;
                var title = Titles[rng.Next(Titles.Length)];
                var message = Messages[rng.Next(Messages.Length)];
                var severity = (Severity)rng.Next(3);

                _hub.AddNotification(title, message, severity);
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on stop/dispose
        }
    }

    public void Dispose()
    {
        Stop();
    }
}

