@using sv_79ab356b9e2a41af8681d336fae5e859.Services
@rendermode InteractiveServer
@implements IDisposable
@inject NotificationHub Hub
@inject NavigationManager Nav

<button class="notification-bell" @onclick="GoToNotifications" title="Notifications">
    <span class="bi bi-bell-fill" aria-hidden="true">🔔</span>
    @if (_unreadCount > 0)
    {
        <span class="badge">@_unreadCount</span>
    }
</button>

@code {
    private int _unreadCount;

    protected override void OnInitialized()
    {
        _unreadCount = Hub.GetUnreadCount();
        Hub.OnChange += HandleStateChange;
    }

    private async Task HandleStateChange()
    {
        _unreadCount = Hub.GetUnreadCount();
        await InvokeAsync(StateHasChanged);
    }

    private void GoToNotifications()
    {
        Nav.NavigateTo("/notifications");
    }

    public void Dispose()
    {
        Hub.OnChange -= HandleStateChange;
    }
}

.notification-bell {
    position: relative;
    background: none;
    border: none;
    cursor: pointer;
    font-size: 1.3rem;
    color: white;
    padding: 0.25rem 0.5rem;
}

.notification-bell .badge {
    position: absolute;
    top: -2px;
    right: -4px;
    background-color: #dc3545;
    color: white;
    border-radius: 50%;
    padding: 0.15rem 0.4rem;
    font-size: 0.7rem;
    font-weight: bold;
    line-height: 1;
    min-width: 1rem;
    text-align: center;
}

