@page "/dashboard"
@rendermode InteractiveServer
@using sv_79ab356b9e2a41af8681d336fae5e859.Services
@implements IDisposable
@inject NotificationHub Hub
@inject SimulatorService Simulator

<PageTitle>Dashboard</PageTitle>

<h3>Dashboard</h3>

<p class="text-muted">A random notification is generated every 15 seconds to simulate server-push events.</p>

<NotificationSummaryPanel />

@code {
    protected override void OnInitialized()
    {
        Simulator.Start();
    }

    public void Dispose()
    {
        Simulator.Stop();
    }
}

@using sv_79ab356b9e2a41af8681d336fae5e859.Services
@implements IDisposable
@inject NotificationHub Hub

<div class="card">
    <div class="card-header">
        <strong>Recent Unread Notifications</strong>
    </div>
    <div class="card-body">
        @if (!_recent.Any())
        {
            <p class="text-muted mb-0">No unread notifications.</p>
        }
        else
        {
            <div class="list-group list-group-flush">
                @foreach (var notification in _recent)
                {
                    <div class="list-group-item d-flex justify-content-between align-items-center">
                        <div>
                            <span class="badge @GetSeverityBadgeClass(notification.Severity) me-2">
                                @notification.Severity
                            </span>
                            <strong>@notification.Title</strong>
                            <br />
                            <small class="text-muted">@notification.Message</small>
                        </div>
                        <button class="btn btn-sm btn-outline-danger" @onclick="() => Dismiss(notification.Id)">
                            Dismiss
                        </button>
                    </div>
                }
            </div>
        }
    </div>
</div>

@code {
    private List<Notification> _recent = [];

    protected override void OnInitialized()
    {
        LoadRecent();
        Hub.OnChange += HandleStateChange;
    }

    private void LoadRecent()
    {
        _recent = Hub.Notifications
            .Where(n => !n.IsRead)
            .OrderByDescending(n => n.Timestamp)
            .Take(3)
            .ToList();
    }

    private async Task HandleStateChange()
    {
        LoadRecent();
        await InvokeAsync(StateHasChanged);
    }

    private void Dismiss(Guid id) => Hub.DismissNotification(id);

    private static string GetSeverityBadgeClass(Severity severity) => severity switch
    {
        Severity.Critical => "bg-danger",
        Severity.Warning => "bg-warning text-dark",
        _ => "bg-info"
    };

    public void Dispose()
    {
        Hub.OnChange -= HandleStateChange;
    }
}

